'use client';
import * as React from 'react';

// The pre-generated static CSS file — contains :root and
// [data-mui-color-scheme="dark"] blocks with all MUI CSS variables.
// Generated by: pnpm -F @mui/material build:theme-css
import '../../../packages/mui-material/default-theme.css';

import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Chip from '@mui/material/Chip';
import Slider from '@mui/material/Slider';
import Stack from '@mui/material/Stack';
import Switch from '@mui/material/Switch';
import TextField from '@mui/material/TextField';
import ToggleButton from '@mui/material/ToggleButton';
import ToggleButtonGroup from '@mui/material/ToggleButtonGroup';
import Typography from '@mui/material/Typography';

// ---------- Dark-mode toggle ------------------------------------------------
// No ThemeProvider in this tree. We flip `data-mui-color-scheme` on
// `document.documentElement` — matching the selectors the generated CSS uses.

type Mode = 'light' | 'dark';

function useDarkMode(): [Mode, (mode: Mode) => void] {
  const [mode, setModeState] = React.useState<Mode>('light');

  const setMode = React.useCallback((next: Mode) => {
    document.documentElement.setAttribute('data-mui-color-scheme', next);
    setModeState(next);
  }, []);

  return [mode, setMode];
}

// ---------- Layout helpers --------------------------------------------------

function Section({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <Box sx={{ mb: 5 }}>
      <Typography
        variant="overline"
        sx={{
          color: 'var(--mui-palette-text-disabled)',
          fontWeight: 700,
          letterSpacing: '0.1em',
          display: 'block',
          mb: 1.5,
        }}
      >
        {label}
      </Typography>
      {children}
    </Box>
  );
}

// ---------- Page ------------------------------------------------------------

function Page({ mode, setMode }: { mode: Mode; setMode: (m: Mode) => void }) {
  const [sliderValue, setSliderValue] = React.useState<number>(40);
  const [chips, setChips] = React.useState(['React', 'CSS vars']);
  const [textValue, setTextValue] = React.useState('');

  function toggleChip(label: string) {
    setChips((prev) =>
      prev.includes(label) ? prev.filter((c) => c !== label) : [...prev, label],
    );
  }

  return (
    <Box
      sx={{
        p: { xs: 3, md: 5 },
        maxWidth: 760,
        mx: 'auto',
        minHeight: '100vh',
        bgcolor: 'var(--mui-palette-background-default)',
        color: 'var(--mui-palette-text-primary)',
      }}
    >
      <Typography variant="h4" sx={{ fontWeight: 700, mb: 0.5 }}>
        Static theme playground
      </Typography>
      <Typography variant="body2" sx={{ color: 'var(--mui-palette-text-secondary)', mb: 4 }}>
        No <code>ThemeProvider</code>, no Emotion runtime. All CSS variables come from{' '}
        <code>default-theme.css</code> — a static file generated once at build time by{' '}
        <code>scripts/buildDefaultThemeCss.mts</code>.
      </Typography>

      {/* ── Dark mode toggle ──────────────────────────────────────────── */}
      <Section label="Dark mode (no re-render — just a DOM attribute flip)">
        <Stack direction="row" spacing={1} sx={{ alignItems: 'center' }}>
          <Typography variant="body2">Light</Typography>
          <Switch
            checked={mode === 'dark'}
            onChange={(event) => setMode(event.target.checked ? 'dark' : 'light')}
          />
          <Typography variant="body2">Dark</Typography>
        </Stack>
        <Typography variant="caption" sx={{ display: 'block', mt: 1, color: 'var(--mui-palette-text-disabled)' }}>
          Toggle calls{' '}
          <code>document.documentElement.setAttribute(&quot;data-mui-color-scheme&quot;, ...)</code>
          . No provider, no JS re-render needed.
        </Typography>
      </Section>

      {/* ── Components ────────────────────────────────────────────────── */}
      <Section label="Buttons (default + color + disabled)">
        <Stack direction="row" spacing={2} useFlexGap sx={{ flexWrap: 'wrap' }}>
          <Button variant="contained">Primary</Button>
          <Button variant="contained" color="secondary">
            Secondary
          </Button>
          <Button variant="outlined">Outlined</Button>
          <Button variant="text">Text</Button>
          <Button variant="contained" disabled>
            Disabled
          </Button>
        </Stack>
      </Section>

      <Section label="Slider (animations confirm the transition fallbacks)">
        <Slider value={sliderValue} onChange={(_, v) => setSliderValue(v as number)} />
        <Typography variant="body2" sx={{ mt: 0.5, color: 'var(--mui-palette-text-secondary)' }}>
          Value: {sliderValue}. Drag the thumb — movement should ease, not snap.
        </Typography>
      </Section>

      <Section label="TextField (color + focus + helper)">
        <Stack spacing={2} sx={{ maxWidth: 400 }}>
          <TextField
            label="Default"
            value={textValue}
            onChange={(event) => setTextValue(event.target.value)}
          />
          <TextField label="Error state" error helperText="This field has an error" />
        </Stack>
      </Section>

      <Section label="Chips (interactive)">
        <Stack direction="row" spacing={1} useFlexGap sx={{ flexWrap: 'wrap' }}>
          {['React', 'CSS vars', 'No Provider', 'Static CSS'].map((label) => (
            <Chip
              key={label}
              label={label}
              color={chips.includes(label) ? 'primary' : 'default'}
              onClick={() => toggleChip(label)}
            />
          ))}
        </Stack>
      </Section>

      <Section label="Switch">
        <Switch defaultChecked />
        <Switch />
        <Switch defaultChecked color="secondary" />
      </Section>

      <Section label="Toggle button group">
        <ToggleButtonGroup value="center" exclusive size="small">
          <ToggleButton value="left">Left</ToggleButton>
          <ToggleButton value="center">Center</ToggleButton>
          <ToggleButton value="right">Right</ToggleButton>
        </ToggleButtonGroup>
      </Section>
    </Box>
  );
}

export default function StaticThemePlayground() {
  const [mode, setMode] = useDarkMode();
  return <Page mode={mode} setMode={setMode} />;
}
